INSERT INTO `message` VALUES ('1f5ed743-eced-40e1-8c9c-3ff53567521c', 'doubao', '1', '{\"id\":\"doubao\",\"name\":\"豆包\",\"avatar\":\"https://lf-flow-web-cdn.doubao.com/obj/flow-doubao/samantha/logo-icon-white-bg.png\",\"type\":\"bot\",\"badge\":null}', '[{\"type\":\"at\",\"content\":\"{\\\"id\\\":\\\"21\\\",\\\"name\\\":\\\"tt\\\",\\\"avatar\\\":\\\"\\\",\\\"type\\\":\\\"admin\\\",\\\"badge\\\":[\\\"diamond\\\",\\\"clover\\\"]}\"},{\"type\":\"text\",\"content\":\"Wolai是一款功能较为丰富且有一定特色的知识管理与协作工具，好不好用取决于个人需求和使用习惯，以下为你详细介绍：\\n\\n### 优点\\n1. **界面简洁美观**：操作界面简洁直观，新用户能够较快上手。比如在创建新笔记、编辑内容时，布局清晰，按钮功能一目了然，减少了用户摸索的时间成本。\\n2. **功能丰富实用**\\n    - **多维表格强大**：支持自由创建和定制各种类型的表格，能方便地整理和分析数据。例如，团队可以用它管理项目任务，清晰呈现任务的负责人、进度、时间节点等信息。\\n    - **知识图谱助力梳理**：能自动生成知识图谱，帮助用户直观地看到知识点之间的关联，有助于构建完整的知识体系。比如学习历史时，可以通过知识图谱清晰地了解各个历史事件、人物之间的关系。\\n    - **丰富的块元素**：提供了多种块元素，如文本、图片、链接、公式、列表等，方便用户灵活组织内容。撰写文档时可轻松**相关元素，使内容更加丰富多样。\\n    - **支持多种格式导入导出**：方便与其他工具进行数据交互。比如可以导入常见的文档格式如Word、Excel等，也能将笔记导出为PDF等格式分享给他人。\\n3. **协作体验良好**\\n    - **实时协作流畅**：多人可同时在线协作编辑，实时看到彼此的修改。团队成员共同编辑一篇文档时，能实时交流想法，提高协作效率。\\n    - **权限管理灵活**：可以精细设置不同人员对不同内容的访问和编辑权限。例如，对于一些机密的项目文档，可严格限定只有特定人员能查看和编辑。\\n4. **云端存储方便**：数据存储在云端，方便用户随时随地通过各种设备访问和编辑自己的笔记和文件，不用担心数据丢失问题。比如在外出办公时，能及时在手机或平板上处理重要文档。\\n5. **支持插件扩展**：拥有丰富的插件生态系统，用户可以根据自身需求安装各种插件来扩展功能。例如安装翻译插件，方便在处理外文资料时快速翻译内容。\\n\\n### 不足\\n1. **学习成本**：功能丰富意味着初次使用时需要花费一些时间来了解和掌握各项功能的使用方法，但官方提供了详细的文档和教程，一定程度上可以帮助用户快速入门。\\n2. **部分高级功能收费**：如一些特定的模板、高级的数据统计分析功能等需要付费订阅高级版才能使用，如果对这些功能需求较高，会增加使用成本。 \\n\"}]', NULL, NULL, 0, 'text', 'group', '2025-05-17 00:47:49.941', '2025-05-17 00:47:49.941');
